import React, { useEffect, useState } from "react";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Myappointments() {
  const [appointments, setAppointments] = useState([]);

  // ✅ FETCH APPOINTMENTS
  useEffect(() => {
    fetch("http://127.0.0.1:8000/my-appointments/", {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => {
        setAppointments(data);
      })
      .catch((err) => console.error(err));
  }, []);

  // ✅ CANCEL APPOINTMENT (FIXED)
  const handleCancel = async (id) => {
    if (!window.confirm("Cancel this appointment?")) return;

    try {
      const res = await fetch(
        `http://127.0.0.1:8000/cancel-appointment/${id}/`,
        {
          method: "POST",   // ✅ IMPORTANT FIX
          headers: {
            Authorization: `Token ${localStorage.getItem("token")}`,
          },
        }
      );

      if (res.ok) {
        alert("Cancelled successfully");

        // ✅ update UI instantly
        setAppointments((prev) =>
          prev.map((a) =>
            a.id === id ? { ...a, status: "cancelled" } : a
          )
        );
      } else {
        alert("Cancel failed");
      }
    } catch (error) {
      console.error(error);
    }
  };

  // ✅ DATE FIX (IMPORTANT)
  const today = new Date();

  const upcoming = appointments.filter(
    (a) =>
      new Date(a.appointment_date) >= today &&
      a.status !== "cancelled"
  );

  const past = appointments.filter(
    (a) =>
      new Date(a.appointment_date) < today ||
      a.status === "completed"
  );

  return (
    <div style={styles.container}>
      <Navbar />

      <div style={styles.main}>

        {/* UPCOMING */}
        <h2>📅 Upcoming Appointments</h2>

        <div style={styles.grid}>
          {upcoming.length > 0 ? (
            upcoming.map((a) => (
              <div key={a.id} style={styles.card}>
                <h3>{a.doctor_name}</h3>

                <p>
                  📅 {a.appointment_date} <br />
                  ⏰ {a.time_slot}
                </p>

                {/* ✅ STATUS FIX */}
                <span
                  style={{
                    ...styles.status,
                    ...(a.status === "confirmed"
                      ? styles.confirmed
                      : a.status === "cancelled"
                      ? styles.cancelled
                      : styles.completed),
                  }}
                >
                  {a.status}
                </span>

                {/* cancel only if not cancelled */}
                {a.status !== "cancelled" && (
                  <button
                    style={styles.cancelButton}
                    onClick={() => handleCancel(a.id)}
                  >
                    Cancel
                  </button>
                )}
              </div>
            ))
          ) : (
            <p>No upcoming appointments</p>
          )}
        </div>

        {/* PAST */}
        <h2>🕘 Past Appointments</h2>

        <div style={styles.grid}>
          {past.length > 0 ? (
            past.map((a) => (
              <div key={a.id} style={styles.card}>
                <h3>{a.doctor_name}</h3>

                <p>📅 {a.appointment_date}</p>

                <span
                  style={{
                    ...styles.status,
                    ...(a.status === "completed"
                      ? styles.completed
                      : styles.cancelled),
                  }}
                >
                  {a.status}
                </span>
              </div>
            ))
          ) : (
            <p>No past appointments</p>
          )}
        </div>

      </div>

      <Footer />
    </div>
  );
}

export default Myappointments;
